  3→export class ShopifyClient {
  4→  private shopDomain: string
  5→  private storefrontAccessToken: string
  6→  private endpoint: string
  7→
  8→  constructor(config: ShopifyConfig) {
  9→    this.shopDomain = config.shopDomain
 10→    this.storefrontAccessToken = config.storefrontAccessToken
 11→    this.endpoint = `https://${this.shopDomain}/api/2024-01/graphql.json`
 12→  }
 13→
 14→  private async query<T>(query: string, variables?: Record<string, unknown>): Promise<T> {
 15→    const response = await fetch(this.endpoint, {
 16→      method: 'POST',
 17→      headers: {
 18→        'Content-Type': 'application/json',
 19→        'X-Shopify-Storefront-Access-Token': this.storefrontAccessToken,
 20→      },
 21→      body: JSON.stringify({ query, variables }),
 22→    })
 23→
 24→    if (!response.ok) {
 25→      throw new Error(`Shopify API error: ${response.statusText}`)
 26→    }
 27→
 28→    const json = await response.json()
 29→
 30→    if (json.errors) {
 31→      throw new Error(`GraphQL error: ${json.errors[0].message}`)
 32→    }
 33→
 34→    return json.data
 35→  }
 36→
 37→  async getProduct(productId: string): Promise<Product> {
 38→    const query = `
 39→      query getProduct($id: ID!) {
 40→        product(id: $id) {
 41→          id
 42→          title
 43→          description
 44→          handle
 45→          priceRange {
 46→            minVariantPrice {
 47→              amount
 48→              currencyCode
 49→            }
 50→          }
 51→          variants(first: 10) {
 52→            edges {
 53→              node {
 54→                id
 55→                title
 56→                price {
 57→                  amount
 58→                  currencyCode
 59→                }
 60→              }
 61→            }
 62→          }
 63→        }
 64→      }
 65→    `
 66→
 67→    const data = await this.query<{ product: Product }>(query, { id: productId })
 68→    return data.product
 69→  }
 70→
 71→  async createCheckout(lineItems: CheckoutLineItem[]): Promise<Checkout> {
 72→    const query = `
 73→      mutation checkoutCreate($input: CheckoutCreateInput!) {
 74→        checkoutCreate(input: $input) {
 75→          checkout {
 76→            id
 77→            webUrl
 78→            lineItems(first: 10) {
 79→              edges {
 80→                node {
 81→                  id
 82→                  title
 83→                  quantity
 84→                }
 85→              }
 86→            }
 87→            totalPrice {
 88→              amount
 89→              currencyCode
 90→            }
 91→          }
 92→          checkoutUserErrors {
 93→            code
 94→            field
 95→            message
 96→          }
 97→        }
 98→      }
 99→    `
100→
101→    const data = await this.query<{
102→      checkoutCreate: {
103→        checkout: Checkout
104→        checkoutUserErrors: Array<{ code: string; field: string[]; message: string }>
105→      }
106→    }>(query, {
107→      input: {
108→        lineItems: lineItems.map((item) => ({
109→          variantId: item.variantId,
110→          quantity: item.quantity,
111→        })),
112→      },
113→    })
114→
115→    if (data.checkoutCreate.checkoutUserErrors.length > 0) {
116→      throw new Error(data.checkoutCreate.checkoutUserErrors[0].message)
117→    }
118→
119→    return data.checkoutCreate.checkout
120→  }
121→
122→  async getCheckout(checkoutId: string): Promise<Checkout> {
123→    const query = `
124→      query getCheckout($id: ID!) {
125→        node(id: $id) {
126→          ... on Checkout {
127→            id
128→            webUrl
129→            completedAt
130→            lineItems(first: 10) {
131→              edges {
132→                node {
133→                  id
134→                  title
135→                  quantity
136→                }
137→              }
138→            }
139→            totalPrice {
140→              amount
141→              currencyCode
142→            }
143→          }
144→        }
145→      }
146→    `
147→
148→    const data = await this.query<{ node: Checkout & { completedAt: string | null } }>(query, {
149→      id: checkoutId,
150→    })
151→    return data.node
152→  }
153→}
