158→export function createShopifyClient(config: ShopifyConfig): ShopifyClient {
159→  clientInstance = new ShopifyClient(config)
160→  return clientInstance
161→}
162→
163→export function getShopifyClient(): ShopifyClient {
164→  if (!clientInstance) {
165→    throw new Error('Shopify client not initialized. Call createShopifyClient first.')
166→  }
167→  return clientInstance
