  4→const UNLOCKS_PREFIX = 'pressy-unlock-'
  5→
  6→export async function unlockContent(
  7→  bookSlug: string,
  8→  data?: { orderId?: string; email?: string }
  9→): Promise<void> {
 10→  const unlockData: UnlockData = {
 11→    bookSlug,
 12→    orderId: data?.orderId,
 13→    email: data?.email,
 14→    unlockedAt: Date.now(),
 15→  }
 16→
 17→  // Store in IndexedDB
 18→  await set(`${UNLOCKS_PREFIX}${bookSlug}`, unlockData)
 19→
 20→  // Also store in localStorage for quick sync checks
 21→  if (typeof localStorage !== 'undefined') {
 22→    localStorage.setItem(`${UNLOCKS_PREFIX}${bookSlug}`, JSON.stringify(unlockData))
 23→  }
 24→}
 25→
 26→export async function isContentUnlocked(bookSlug: string): Promise<boolean> {
 27→  // Quick check localStorage first
 28→  if (typeof localStorage !== 'undefined') {
 29→    const stored = localStorage.getItem(`${UNLOCKS_PREFIX}${bookSlug}`)
 30→    if (stored) return true
 31→  }
 32→
 33→  // Check IndexedDB
 34→  try {
 35→    const data = await get<UnlockData>(`${UNLOCKS_PREFIX}${bookSlug}`)
 36→    return !!data
 37→  } catch {
 38→    return false
 39→  }
 40→}
 41→
 42→export async function getUnlockData(bookSlug: string): Promise<UnlockData | null> {
 43→  try {
 44→    const data = await get<UnlockData>(`${UNLOCKS_PREFIX}${bookSlug}`)
 45→    return data || null
 46→  } catch {
 47→    return null
 48→  }
 49→}
 50→
 51→export async function revokeUnlock(bookSlug: string): Promise<void> {
 52→  await del(`${UNLOCKS_PREFIX}${bookSlug}`)
 53→
 54→  if (typeof localStorage !== 'undefined') {
 55→    localStorage.removeItem(`${UNLOCKS_PREFIX}${bookSlug}`)
 56→  }
 57→}
 58→
 59→export async function verifyPurchase(
 60→  bookSlug: string,
 61→  orderId: string
 62→): Promise<boolean> {
 63→  // In a production environment, this would verify with your backend
 64→  // which would check with Shopify's API
 65→  const unlockData = await getUnlockData(bookSlug)
 66→
 67→  if (!unlockData) return false
 68→  if (!unlockData.orderId) return false
 69→
 70→  return unlockData.orderId === orderId
 71→}
 72→
 73→// Check URL params for checkout return and auto-unlock
 74→export async function handleCheckoutReturn(): Promise<{
 75→  unlocked: boolean
 76→  bookSlug?: string
 77→}> {
 78→  if (typeof window === 'undefined') {
 79→    return { unlocked: false }
 80→  }
 81→
 82→  const params = new URLSearchParams(window.location.search)
 83→  const checkoutSuccess = params.get('checkout_success')
 84→  const bookSlug = params.get('book')
 85→  const orderId = params.get('order_id')
 86→
 87→  if (checkoutSuccess === 'true' && bookSlug) {
 88→    await unlockContent(bookSlug, { orderId: orderId || undefined })
 89→
 90→    // Clean up URL params
 91→    const url = new URL(window.location.href)
 92→    url.searchParams.delete('checkout_success')
 93→    url.searchParams.delete('book')
 94→    url.searchParams.delete('order_id')
 95→    window.history.replaceState({}, '', url.toString())
 96→
 97→    return { unlocked: true, bookSlug }
 98→  }
 99→
100→  return { unlocked: false }
101→}
