import type { CookiePayload } from './types.js'

const ENCODER = new TextEncoder()

async function getSigningKey(secret: string): Promise<CryptoKey> {
  return crypto.subtle.importKey(
    'raw',
    ENCODER.encode(secret),
    { name: 'HMAC', hash: 'SHA-256' },
    false,
    ['sign', 'verify'],
  )
}

function base64url(buffer: ArrayBuffer): string {
  const bytes = new Uint8Array(buffer)
  let binary = ''
  for (const b of bytes) binary += String.fromCharCode(b)
  return btoa(binary).replace(/\+/g, '-').replace(/\//g, '_').replace(/=+$/, '')
}

function base64urlDecode(str: string): Uint8Array {
  const padded = str.replace(/-/g, '+').replace(/_/g, '/') + '=='.slice(0, (4 - (str.length % 4)) % 4)
  const binary = atob(padded)
  const bytes = new Uint8Array(binary.length)
  for (let i = 0; i < binary.length; i++) bytes[i] = binary.charCodeAt(i)
  return bytes
}

export function cookieName(bookSlug: string): string {
  return `pressy-auth-${bookSlug}`
}

export async function signCookie(payload: CookiePayload, secret: string): Promise<string> {
  const key = await getSigningKey(secret)
  const payloadJson = JSON.stringify(payload)
  const payloadB64 = base64url(ENCODER.encode(payloadJson))
  const signature = await crypto.subtle.sign('HMAC', key, ENCODER.encode(payloadB64))
  const sigB64 = base64url(signature)
  return `${payloadB64}.${sigB64}`
}

export async function verifyCookie(cookieValue: string, secret: string): Promise<CookiePayload | null> {
  const dotIdx = cookieValue.indexOf('.')
  if (dotIdx === -1) return null

  const payloadB64 = cookieValue.slice(0, dotIdx)
  const sigB64 = cookieValue.slice(dotIdx + 1)

  try {
    const key = await getSigningKey(secret)
    const sigBytes = base64urlDecode(sigB64)
    const valid = await crypto.subtle.verify('HMAC', key, sigBytes, ENCODER.encode(payloadB64))
    if (!valid) return null

    const payloadBytes = base64urlDecode(payloadB64)
    const payloadJson = new TextDecoder().decode(payloadBytes)
    return JSON.parse(payloadJson) as CookiePayload
  } catch {
    return null
  }
}

export function setCookieHeader(name: string, value: string): string {
  return `${name}=${value}; HttpOnly; Secure; SameSite=Lax; Path=/; Max-Age=31536000`
}

export function parseCookies(header: string): Record<string, string> {
  const cookies: Record<string, string> = {}
  for (const pair of header.split(';')) {
    const [key, ...rest] = pair.trim().split('=')
    if (key) cookies[key.trim()] = rest.join('=').trim()
  }
  return cookies
}

