    const activeRange = chapterRanges.find((r) => r.slug === activeChapterSlug);
    if (!activeRange) return;

    const pagesFromEnd = activeRange.endPage - currentPage;
    if (pagesFromEnd > 2) return;

    // Find the next chapter to preload
