  const handleFontSizeChange = useCallback(
    (delta: number) => {
      setFontScale((prev) => {
        const next =
          Math.round(Math.max(0.8, Math.min(1.5, prev + delta)) * 10) / 10;
        localStorage.setItem("pressy-font-size", String(next));
