      hasRestoredRef.current = true;
      setAwaitingRestore(false);
      return;
    }

    onRestoreProgress().then((data) => {
      if (hasRestoredRef.current) {
        setAwaitingRestore(false);
        return;
      }

      const currentTotalPages = totalPagesRef.current;

      if (!data || data.page <= 0) {
        hasRestoredRef.current = true;
        setAwaitingRestore(false);
        return;
