    currentPage,
    activeChapterSlug,
    chapterRanges,
    isMultiChapter,
    chapterMapData,
    loadedChapters,
    allChapters,
  ]);

  // Detect chapter boundary crossings and update URL / active chapter
  useEffect(() => {
