      (r) => currentPage >= r.startPage && currentPage <= r.endPage
    );
    if (!currentRange || currentRange.slug === activeChapterSlug) return;

    const prevSlug = activeChapterSlug;
    setActiveChapterSlug(currentRange.slug);

