  1→import type { Env, PressyManifest, PressyBookManifest } from './types.js'
  2→import { parseCookies, verifyCookie, cookieName } from './auth.js'
  3→import {
  4→  handleCheckout,
  5→  handleWebhook,
  6→  handleAuthCallback,
  7→  handleAuthStatus,
  8→  handleRecoverPurchase,
  9→} from './stripe.js'
 10→
 11→let cachedManifest: PressyManifest | null = null
 12→
 13→async function loadManifest(env: Env): Promise<PressyManifest> {
 14→  if (cachedManifest) return cachedManifest
 15→
 16→  const response = await env.ASSETS.fetch(new Request('https://placeholder/_pressy/manifest.json'))
 17→  if (!response.ok) {
 18→    throw new Error(`Failed to load _pressy/manifest.json: ${response.status}`)
 19→  }
 20→  cachedManifest = (await response.json()) as PressyManifest
 21→  return cachedManifest
 22→}
 23→
 24→function matchChapterRoute(pathname: string): { bookSlug: string; chapterSlug: string } | null {
 25→  // Match /books/{bookSlug}/{chapterSlug} with optional trailing slash
 26→  const match = pathname.match(/^\/books\/([^/]+)\/([^/]+)\/?$/)
 27→  if (!match) return null
 28→  return { bookSlug: match[1], chapterSlug: match[2] }
 29→}
 30→
 31→function isChapterPaid(
 32→  book: PressyBookManifest,
 33→  chapterSlug: string,
 34→): boolean {
 35→  if (!book.paywall?.enabled) return false
 36→
 37→  const chapter = book.chapters.find((ch) => ch.slug === chapterSlug)
 38→  if (!chapter) return false
 39→
 40→  return chapter.order >= book.paywall.previewChapters
 41→}
 42→
 43→async function isAuthorized(
 44→  request: Request,
 45→  bookSlug: string,
 46→  secret: string,
 47→): Promise<boolean> {
 48→  const cookieHeader = request.headers.get('cookie')
 49→  if (!cookieHeader) return false
 50→
 51→  const cookies = parseCookies(cookieHeader)
 52→  const authCookie = cookies[cookieName(bookSlug)]
 53→  if (!authCookie) return false
 54→
 55→  const payload = await verifyCookie(authCookie, secret)
 56→  return payload !== null && payload.book === bookSlug
 57→}
 58→
 59→interface PressyContext {
 60→  request: Request
 61→  env: Env
 62→  next: () => Promise<Response>
 63→}
 64→
 65→export function createPressyMiddleware() {
 66→  return async (context: PressyContext): Promise<Response> => {
 67→    const { request, env, next } = context
 68→    const url = new URL(request.url)
 69→    const pathname = url.pathname
 70→
 71→    // Route API requests
 72→    if (pathname.startsWith('/api/')) {
 73→      return handleApiRoute(request, env, pathname, url)
 74→    }
 75→
 76→    // Check if this is a chapter URL that needs paywall enforcement
 77→    const chapterMatch = matchChapterRoute(pathname)
 78→    if (!chapterMatch) {
 79→      return next()
 80→    }
 81→
 82→    let manifest: PressyManifest
 83→    try {
 84→      manifest = await loadManifest(env)
 85→    } catch {
 86→      // If manifest can't be loaded, pass through
 87→      return next()
 88→    }
 89→
 90→    const book = manifest.books.find((b) => b.slug === chapterMatch.bookSlug)
 91→    if (!book) {
 92→      return next()
 93→    }
 94→
 95→    if (!isChapterPaid(book, chapterMatch.chapterSlug)) {
 96→      return next()
 97→    }
 98→
 99→    // Chapter is paid — check authorization
100→    const authorized = await isAuthorized(request, book.slug, env.COOKIE_SECRET)
101→    if (authorized) {
102→      return next()
103→    }
104→
105→    // Not authorized — redirect to book page with purchase prompt
106→    return new Response(null, {
107→      status: 302,
108→      headers: { Location: `/books/${book.slug}/?purchase=true` },
109→    })
110→  }
111→}
112→
113→async function handleApiRoute(
114→  request: Request,
115→  env: Env,
116→  pathname: string,
117→  url: URL,
118→): Promise<Response> {
119→  let manifest: PressyManifest
120→  try {
121→    manifest = await loadManifest(env)
122→  } catch {
123→    return new Response('Manifest not found', { status: 500 })
124→  }
125→
126→  // GET /api/checkout?book=SLUG
127→  if (pathname === '/api/checkout' && request.method === 'GET') {
128→    const bookSlug = url.searchParams.get('book')
129→    if (!bookSlug) {
130→      return new Response('Missing book parameter', { status: 400 })
131→    }
132→    const book = manifest.books.find((b) => b.slug === bookSlug)
133→    if (!book) {
134→      return new Response('Book not found', { status: 404 })
135→    }
136→    return handleCheckout(request, env, book)
137→  }
138→
139→  // POST /api/stripe-webhook
140→  if (pathname === '/api/stripe-webhook' && request.method === 'POST') {
141→    return handleWebhook(request, env)
142→  }
143→
144→  // GET /api/auth/callback?session_id=xxx
145→  if (pathname === '/api/auth/callback' && request.method === 'GET') {
146→    return handleAuthCallback(request, env, manifest)
147→  }
148→
149→  // GET /api/auth/status?book=SLUG
150→  if (pathname === '/api/auth/status' && request.method === 'GET') {
151→    const bookSlug = url.searchParams.get('book')
152→    if (!bookSlug) {
153→      return new Response(JSON.stringify({ authorized: false }), {
154→        headers: { 'Content-Type': 'application/json' },
155→      })
156→    }
157→    const authorized = await isAuthorized(request, bookSlug, env.COOKIE_SECRET)
158→    return handleAuthStatus(request, env, authorized)
159→  }
160→
161→  // POST /api/auth/recover?email=xxx&book=SLUG
162→  if (pathname === '/api/auth/recover' && request.method === 'GET') {
163→    return handleRecoverPurchase(request, env, manifest)
164→  }
