export interface Env {
  ASSETS: Fetcher
  PRESSY_KV: KVNamespace
  STRIPE_SECRET_KEY: string
  STRIPE_WEBHOOK_SECRET: string
  COOKIE_SECRET: string
}

export interface PressyManifest {
  books: PressyBookManifest[]
}

export interface PressyBookManifest {
  slug: string
  paywall?: {
    enabled: boolean
    previewChapters: number
    price?: string
    stripeProductId?: string
  }
  chapters: Array<{
    slug: string
    order: number
  }>
}

export interface PurchaseRecord {
  sessionId: string
  email: string
  bookSlug: string
  amount: number
  purchasedAt: string
}

export interface CookiePayload {
  book: string
  email: string
  purchasedAt: string
  sessionId: string
}

import type { CookiePayload } from './types.js'

const ENCODER = new TextEncoder()

async function getSigningKey(secret: string): Promise<CryptoKey> {
  return crypto.subtle.importKey(
    'raw',
    ENCODER.encode(secret),
    { name: 'HMAC', hash: 'SHA-256' },
    false,
    ['sign', 'verify'],
  )
}

function base64url(buffer: ArrayBuffer): string {
  const bytes = new Uint8Array(buffer)
  let binary = ''
  for (const b of bytes) binary += String.fromCharCode(b)
  return btoa(binary).replace(/\+/g, '-').replace(/\//g, '_').replace(/=+$/, '')
}

function base64urlDecode(str: string): Uint8Array {
  const padded = str.replace(/-/g, '+').replace(/_/g, '/') + '=='.slice(0, (4 - (str.length % 4)) % 4)
  const binary = atob(padded)
  const bytes = new Uint8Array(binary.length)
  for (let i = 0; i < binary.length; i++) bytes[i] = binary.charCodeAt(i)
  return bytes
}

export function cookieName(bookSlug: string): string {
  return `pressy-auth-${bookSlug}`
}

export async function signCookie(payload: CookiePayload, secret: string): Promise<string> {
  const key = await getSigningKey(secret)
  const payloadJson = JSON.stringify(payload)
  const payloadB64 = base64url(ENCODER.encode(payloadJson).buffer as ArrayBuffer)
  const signature = await crypto.subtle.sign('HMAC', key, ENCODER.encode(payloadB64))
  const sigB64 = base64url(signature)
  return `${payloadB64}.${sigB64}`
}

export async function verifyCookie(cookieValue: string, secret: string): Promise<CookiePayload | null> {
  const dotIdx = cookieValue.indexOf('.')
  if (dotIdx === -1) return null

  const payloadB64 = cookieValue.slice(0, dotIdx)
  const sigB64 = cookieValue.slice(dotIdx + 1)

  try {
    const key = await getSigningKey(secret)
    const sigBytes = base64urlDecode(sigB64)
    const valid = await crypto.subtle.verify('HMAC', key, sigBytes.buffer as ArrayBuffer, ENCODER.encode(payloadB64))
    if (!valid) return null

    const payloadBytes = base64urlDecode(payloadB64)
    const payloadJson = new TextDecoder().decode(payloadBytes)
    return JSON.parse(payloadJson) as CookiePayload
  } catch {
    return null
  }
}

export function setCookieHeader(name: string, value: string): string {
  return `${name}=${value}; HttpOnly; Secure; SameSite=Lax; Path=/; Max-Age=31536000`
}

export function parseCookies(header: string): Record<string, string> {
  const cookies: Record<string, string> = {}
  for (const pair of header.split(';')) {
    const [key, ...rest] = pair.trim().split('=')
    if (key) cookies[key.trim()] = rest.join('=').trim()
  }
  return cookies
}

import Stripe from 'stripe'
import type { Env, PressyBookManifest, PurchaseRecord } from './types.js'
import { signCookie, setCookieHeader, cookieName } from './auth.js'

function getStripe(secretKey: string): Stripe {
  return new Stripe(secretKey, { apiVersion: '2025-02-24.acacia' })
}

function getBaseUrl(request: Request): string {
  const url = new URL(request.url)
  return `${url.protocol}//${url.host}`
}

export async function handleCheckout(
  request: Request,
  env: Env,
  book: PressyBookManifest,
): Promise<Response> {
  const stripe = getStripe(env.STRIPE_SECRET_KEY)
  const baseUrl = getBaseUrl(request)

  if (!book.paywall?.stripeProductId) {
    return new Response('Book has no Stripe product configured', { status: 400 })
  }

  const session = await stripe.checkout.sessions.create({
    mode: 'payment',
    line_items: [{ price: book.paywall.stripeProductId, quantity: 1 }],
    success_url: `${baseUrl}/api/auth/callback?session_id={CHECKOUT_SESSION_ID}`,
    cancel_url: `${baseUrl}/books/${book.slug}/`,
    metadata: { bookSlug: book.slug },
  })

  return Response.redirect(session.url!, 303)
}

export async function handleWebhook(
  request: Request,
  env: Env,
): Promise<Response> {
  const stripe = getStripe(env.STRIPE_SECRET_KEY)
  const body = await request.text()
  const signature = request.headers.get('stripe-signature')

  if (!signature) {
    return new Response('Missing stripe-signature header', { status: 400 })
  }

  let event: Stripe.Event
  try {
    event = await stripe.webhooks.constructEventAsync(body, signature, env.STRIPE_WEBHOOK_SECRET)
  } catch (err) {
    return new Response(`Webhook signature verification failed: ${err}`, { status: 400 })
  }

  if (event.type === 'checkout.session.completed') {
    const session = event.data.object as Stripe.Checkout.Session
    const bookSlug = session.metadata?.bookSlug
    const email = session.customer_details?.email

    if (bookSlug && email) {
      const record: PurchaseRecord = {
        sessionId: session.id,
        email,
        bookSlug,
        amount: session.amount_total || 0,
        purchasedAt: new Date().toISOString(),
      }

      await env.PRESSY_KV.put(
        `purchase:${email}:${bookSlug}`,
        JSON.stringify(record),
        { expirationTtl: 5 * 365 * 24 * 60 * 60 }, // 5 years
      )
    }
  }

  return new Response('ok', { status: 200 })
}

export async function handleAuthCallback(
  request: Request,
  env: Env,
  manifest: { books: PressyBookManifest[] },
): Promise<Response> {
  const url = new URL(request.url)
  const sessionId = url.searchParams.get('session_id')

  if (!sessionId) {
    return new Response('Missing session_id', { status: 400 })
  }

  const stripe = getStripe(env.STRIPE_SECRET_KEY)
  const session = await stripe.checkout.sessions.retrieve(sessionId)

  if (session.payment_status !== 'paid') {
    return new Response('Payment not completed', { status: 402 })
  }

  const bookSlug = session.metadata?.bookSlug
  const email = session.customer_details?.email
  if (!bookSlug || !email) {
    return new Response('Invalid session metadata', { status: 400 })
  }

  const book = manifest.books.find((b) => b.slug === bookSlug)
  if (!book) {
    return new Response('Book not found', { status: 404 })
  }

  // Record purchase in KV (in case webhook hasn't fired yet)
  const record: PurchaseRecord = {
    sessionId: session.id,
    email,
    bookSlug,
    amount: session.amount_total || 0,
    purchasedAt: new Date().toISOString(),
  }
  await env.PRESSY_KV.put(
    `purchase:${email}:${bookSlug}`,
    JSON.stringify(record),
    { expirationTtl: 5 * 365 * 24 * 60 * 60 },
  )

  // Sign and set auth cookie
  const cookieValue = await signCookie(
    { book: bookSlug, email, purchasedAt: record.purchasedAt, sessionId },
    env.COOKIE_SECRET,
  )

  // Redirect to first paid chapter
  const firstPaidChapter = book.chapters.find(
    (ch) => ch.order >= (book.paywall?.previewChapters || 0),
  )
  const redirectPath = firstPaidChapter
    ? `/books/${bookSlug}/${firstPaidChapter.slug}/`
    : `/books/${bookSlug}/`

  return new Response(null, {
    status: 302,
    headers: {
      Location: redirectPath,
      'Set-Cookie': setCookieHeader(cookieName(bookSlug), cookieValue),
    },
  })
}

export async function handleAuthStatus(
  request: Request,
  env: Env,
  authorized: boolean,
): Promise<Response> {
  return new Response(JSON.stringify({ authorized }), {
    headers: { 'Content-Type': 'application/json' },
  })
}

export async function handleRecoverPurchase(
  request: Request,
  env: Env,
  manifest: { books: PressyBookManifest[] },
): Promise<Response> {
  const url = new URL(request.url)
  const email = url.searchParams.get('email')
  const bookSlug = url.searchParams.get('book')

  if (!email || !bookSlug) {
    return new Response(JSON.stringify({ error: 'Missing email or book' }), {
      status: 400,
      headers: { 'Content-Type': 'application/json' },
    })
  }

  const record = await env.PRESSY_KV.get(`purchase:${email}:${bookSlug}`)
  if (!record) {
    return new Response(JSON.stringify({ error: 'No purchase found' }), {
      status: 404,
      headers: { 'Content-Type': 'application/json' },
    })
  }

  const purchase: PurchaseRecord = JSON.parse(record)

  // Issue a new cookie
  const cookieValue = await signCookie(
    { book: bookSlug, email, purchasedAt: purchase.purchasedAt, sessionId: purchase.sessionId },
    env.COOKIE_SECRET,
  )

  return new Response(JSON.stringify({ recovered: true }), {
    headers: {
      'Content-Type': 'application/json',
      'Set-Cookie': setCookieHeader(cookieName(bookSlug), cookieValue),
    },
  })
}

